def p(g):
    H = len(g)
    W = len(g[0])
    # Find bounding box of non-zero cells
    min_r = H
    max_r = -1
    min_c = W
    max_c = -1
    for i in range(H):
        for j in range(W):
            if g[i][j]:
                if i < min_r: min_r = i
                if i > max_r: max_r = i
                if j < min_c: min_c = j
                if j > max_c: max_c = j
    br, bc = min_r, min_c
    tall = max_r - br + 1
    wide = max_c - bc + 1
    A = g[br][bc]
    # Find B (the other non-zero color inside the box)
    B = None
    for i in range(br, br + tall):
        for j in range(bc, bc + wide):
            if g[i][j] and g[i][j] != A:
                B = g[i][j]
                break
        if B is not None:
            break
    # inner area boundaries (half-open intervals)
    ir_lo = br + 2
    ir_hi = br + tall - 2
    ic_lo = bc + 2
    ic_hi = bc + wide - 2
    rows_set = set()
    cols_set = set()
    # Barnacles are B cells that lie on the second perimeter,
    # i.e., not inside the inner area.
    for i in range(br, br + tall):
        for j in range(bc, bc + wide):
            if g[i][j] == B:
                if not (i >= ir_lo and i < ir_hi and j >= ic_lo and j < ic_hi):
                    rows_set.add(i - ir_lo)
                    cols_set.add(j - ic_lo)
    out = [[0] * W for _ in range(H)]
    for i in range(H):
        for j in range(W):
            if i < br or i > max_r or j < bc or j > max_c:
                # outside box
                v = 0
                if ir_lo <= i < ir_hi and (i - ir_lo) in rows_set:
                    v = B
                if ic_lo <= j < ic_hi and (j - ic_lo) in cols_set:
                    v = B
                out[i][j] = v
            else:
                # inside box
                if i < ir_lo or i >= ir_hi or j < ic_lo or j >= ic_hi:
                    # border of the box
                    out[i][j] = A
                else:
                    # inner rectangle
                    if (i - ir_lo) in rows_set or (j - ic_lo) in cols_set:
                        out[i][j] = A
                    else:
                        out[i][j] = B
    return out

